async function loadMap(name: string): Promise<MapData> {
  try {
    const handle = await fs.open(name, 'r');
    try {
      const stats = await handle.stat();
      const buf = Buffer.alloc(stats.size);
      await handle.read(buf, 0, stats.size, 0);
      return parseMap(buf);
    } finally {
      await handle.close();
    }
  } catch (err: unknown) {
    if (err instanceof FileNotFoundError) {
      throw new MapLoadError(`Map '${name}' not found`, { cause: err });
    }
    throw new MapLoadError(`Failed to load map '${name}'`, { cause: err });
  }
}
